sql:
SELECT country_id, goals_scored_avg
FROM statistics
ORDER BY goals_scored_avg DESC;

external_knowledge:
- 'quarter = 1' indicates that the country reached the quarter-finals of the tournament;
- 'semi = 1' indicates that the country reached the semi-finals of the tournament;
- 'Better' performance means the country scored more goals than it conceded;
- 'Worse' performance means the country conceded more goals than it scored;
- 'Equal' performance means the country scored the same number of goals as it conceded.

- The "grand theater of soccer" refers to the context of international soccer tournaments;
- The "final act of the tournament" refers to the final stage of the tournament;
- The "most recent performance metrics" refer to the latest year's data in the `performance_metrics` table;
- The "most prolific scorer" refers to the country with the highest average goals scored.

sql:
SELECT country_id, AVG(goals_scored_avg) AS avg_goals_scored_avg
FROM statistics
GROUP BY country_id;
